# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <array>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <limits>
#include <chrono>

const int GRID_SIZE = 10;
const int NUM_TURNS = 100;
const int NUM_FLAVORS = 3;

const int DR[] = {-1, 1, 0, 0};
const int DC[] = {0, 0, -1, 1};
const char DIR_CHARS[] = {'F', 'B', 'L', 'R'};
const int NUM_DIRECTIONS = 4;

std::array<int, NUM_TURNS> G_FLAVOR_SEQUENCE;
std::array<int, NUM_FLAVORS + 1> G_flavor_total_counts;

// Target zones: each flavor gets a strip of columns
std::array<int, NUM_FLAVORS + 1> G_target_col_min;
std::array<int, NUM_FLAVORS + 1> G_target_col_max;

// Depth-2 lookahead - optimal sample counts for time budget
const int MAX_LOOKAHEAD_DEPTH = 2;
static constexpr std::array<int, MAX_LOOKAHEAD_DEPTH> NUM_SAMPLES_CONFIG = {12, 5};

struct XorshiftRNG {
    uint64_t x;
    XorshiftRNG() : x(88172645463325252ULL) {}
    void seed(uint64_t s) { x = s ? s : 88172645463325252ULL; }
    uint64_t next() {
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        return x;
    }
    int uniform_int(int min_val, int max_val) {
        if (min_val >= max_val) return min_val;
        uint64_t range = static_cast<uint64_t>(max_val) - min_val + 1;
        return min_val + static_cast<int>(next() % range);
    }
};
XorshiftRNG rng;

struct GameState {
    std::array<std::array<int, GRID_SIZE>, GRID_SIZE> board;
    int num_candies;
    int turn_num;

    GameState() : num_candies(0), turn_num(0) {
        for (int i = 0; i < GRID_SIZE; ++i) board[i].fill(0);
    }

    void place_candy(int r, int c, int flavor) {
        board[r][c] = flavor;
        num_candies++;
    }

    std::pair<int, int> find_pth_empty_cell(int p) const {
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] == 0) {
                    count++;
                    if (count == p) return {r, c};
                }
            }
        }
        return {-1, -1};
    }

    int count_empty_cells() const {
        return GRID_SIZE * GRID_SIZE - num_candies;
    }

    void apply_tilt(int dir_idx) {
        if (dir_idx == 0) { // F (Up)
            for (int c = 0; c < GRID_SIZE; ++c) {
                int wr = 0;
                for (int r = 0; r < GRID_SIZE; ++r) {
                    if (board[r][c] != 0) {
                        if (r != wr) { board[wr][c] = board[r][c]; board[r][c] = 0; }
                        wr++;
                    }
                }
            }
        } else if (dir_idx == 1) { // B (Down)
            for (int c = 0; c < GRID_SIZE; ++c) {
                int wr = GRID_SIZE - 1;
                for (int r = GRID_SIZE - 1; r >= 0; --r) {
                    if (board[r][c] != 0) {
                        if (r != wr) { board[wr][c] = board[r][c]; board[r][c] = 0; }
                        wr--;
                    }
                }
            }
        } else if (dir_idx == 2) { // L (Left)
            for (int r = 0; r < GRID_SIZE; ++r) {
                int wc = 0;
                for (int c = 0; c < GRID_SIZE; ++c) {
                    if (board[r][c] != 0) {
                        if (c != wc) { board[r][wc] = board[r][c]; board[r][c] = 0; }
                        wc++;
                    }
                }
            }
        } else { // R (Right)
            for (int r = 0; r < GRID_SIZE; ++r) {
                int wc = GRID_SIZE - 1;
                for (int c = GRID_SIZE - 1; c >= 0; --c) {
                    if (board[r][c] != 0) {
                        if (c != wc) { board[r][wc] = board[r][c]; board[r][c] = 0; }
                        wc--;
                    }
                }
            }
        }
    }

    // Combined evaluation: BFS connectivity + adjacency + target zone + compactness
    double evaluate() const {
        double phase = static_cast<double>(turn_num) / NUM_TURNS;

        // BFS connectivity scoring (sum of squares)
        long long sum_sq = 0;
        std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
        for (int i = 0; i < GRID_SIZE; ++i) visited[i].fill(false);

        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0 && !visited[r][c]) {
                    int flavor = board[r][c];
                    int comp_size = 0;
                    // BFS
                    std::array<std::pair<int,int>, 100> q;
                    int head = 0, tail = 0;
                    q[tail++] = {r, c};
                    visited[r][c] = true;
                    while (head < tail) {
                        auto [cr, cc] = q[head++];
                        comp_size++;
                        for (int d = 0; d < 4; ++d) {
                            int nr = cr + DR[d], nc = cc + DC[d];
                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                                !visited[nr][nc] && board[nr][nc] == flavor) {
                                visited[nr][nc] = true;
                                q[tail++] = {nr, nc};
                            }
                        }
                    }
                    sum_sq += (long long)comp_size * comp_size;
                }
            }
        }

        // Adjacent same-flavor pairs (horizontal and vertical)
        int adj_pairs = 0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] == 0) continue;
                if (c + 1 < GRID_SIZE && board[r][c + 1] == board[r][c]) adj_pairs++;
                if (r + 1 < GRID_SIZE && board[r + 1][c] == board[r][c]) adj_pairs++;
            }
        }

        // Target zone penalty: how far candies are from their assigned column strips
        double zone_penalty = 0.0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int f = board[r][c];
                if (f == 0) continue;
                if (c < G_target_col_min[f]) zone_penalty += (G_target_col_min[f] - c);
                else if (c > G_target_col_max[f]) zone_penalty += (c - G_target_col_max[f]);
            }
        }

        // Compactness: sum of distances to flavor centroid
        std::array<double, NUM_FLAVORS + 1> sr = {}, sc = {};
        std::array<int, NUM_FLAVORS + 1> cnt = {};
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int f = board[r][c];
                if (f == 0) continue;
                cnt[f]++;
                sr[f] += r;
                sc[f] += c;
            }
        }
        double compact_penalty = 0.0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int f = board[r][c];
                if (f == 0 || cnt[f] <= 1) continue;
                double cr = sr[f] / cnt[f], cc = sc[f] / cnt[f];
                compact_penalty += std::abs(r - cr) + std::abs(c - cc);
            }
        }

        // Weights that transition across phases
        double w_conn = 20.0 + 80.0 * phase;
        double w_adj = 3.0 + 10.0 * phase;
        double w_zone = -(15.0 * (1.0 - 0.8 * phase));
        double w_compact = -(1.5 * (1.0 - 0.9 * phase));

        return w_conn * sum_sq + w_adj * adj_pairs + w_zone * zone_penalty + w_compact * compact_penalty;
    }
};

double eval_lookahead(const GameState& state, int turn_just_processed, int depth_remaining);

int decide_tilt_direction(const GameState& gs) {
    double best_eval = std::numeric_limits<double>::lowest();
    int best_dir = 0;

    for (int d = 0; d < NUM_DIRECTIONS; ++d) {
        GameState gs_tilted = gs;
        gs_tilted.apply_tilt(d);
        double val = eval_lookahead(gs_tilted, gs.turn_num, MAX_LOOKAHEAD_DEPTH);
        if (val > best_eval) {
            best_eval = val;
            best_dir = d;
        }
    }
    return best_dir;
}

double eval_lookahead(const GameState& state, int turn_just_processed, int depth_remaining) {
    if (depth_remaining == 0 || turn_just_processed >= NUM_TURNS) {
        return state.evaluate();
    }

    int num_empty = state.count_empty_cells();
    if (num_empty == 0) return state.evaluate();

    int next_flavor = G_FLAVOR_SEQUENCE[turn_just_processed];
    int sample_idx = MAX_LOOKAHEAD_DEPTH - depth_remaining;
    int num_samples = std::min(NUM_SAMPLES_CONFIG[sample_idx], num_empty);

    if (num_samples == 0) return state.evaluate();

    double sum_eval = 0.0;
    for (int s = 0; s < num_samples; ++s) {
        int p_val;
        if (num_samples >= num_empty) {
            p_val = s + 1;
        } else {
            p_val = rng.uniform_int(1, num_empty);
        }

