# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <array>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <limits>
#include <chrono>

const int GRID_SIZE = 10;
const int NUM_TURNS = 100;
const int NUM_FLAVORS = 3;

const int DR[] = {-1, 1, 0, 0};
const int DC[] = {0, 0, -1, 1};
const char DIR_CHARS[] = {'F', 'B', 'L', 'R'};
const int NUM_DIRECTIONS = 4;

std::array<int, NUM_TURNS> G_FLAVOR_SEQUENCE;

struct XorshiftRNG {
    uint64_t x;
    XorshiftRNG() : x(88172645463325252ULL) {}
    void seed(uint64_t s) { x = s ? s : 88172645463325252ULL; }
    uint64_t next() {
        x ^= x << 13;
        x ^= x >> 7;
        x ^= x << 17;
        return x;
    }
    int uniform_int(int min_val, int max_val) {
        if (min_val >= max_val) return min_val;
        uint64_t range = static_cast<uint64_t>(max_val) - min_val + 1;
        return min_val + static_cast<int>(next() % range);
    }
};
XorshiftRNG rng;

struct GameState {
    std::array<std::array<int, GRID_SIZE>, GRID_SIZE> board;
    int num_candies;
    int turn_num;

    GameState() : num_candies(0), turn_num(0) {
        for (int i = 0; i < GRID_SIZE; ++i) board[i].fill(0);
    }

    void place_candy(int r, int c, int flavor) {
        board[r][c] = flavor;
        num_candies++;
    }

    std::pair<int, int> find_pth_empty_cell(int p) const {
        int count = 0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] == 0) {
                    count++;
                    if (count == p) return {r, c};
                }
            }
        }
        return {-1, -1};
    }

    int count_empty_cells() const {
        return GRID_SIZE * GRID_SIZE - num_candies;
    }

    void apply_tilt(int dir_idx) {
        if (dir_idx == 0) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int wr = 0;
                for (int r = 0; r < GRID_SIZE; ++r) {
                    if (board[r][c] != 0) {
                        if (r != wr) { board[wr][c] = board[r][c]; board[r][c] = 0; }
                        wr++;
                    }
                }
            }
        } else if (dir_idx == 1) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                int wr = GRID_SIZE - 1;
                for (int r = GRID_SIZE - 1; r >= 0; --r) {
                    if (board[r][c] != 0) {
                        if (r != wr) { board[wr][c] = board[r][c]; board[r][c] = 0; }
                        wr--;
                    }
                }
            }
        } else if (dir_idx == 2) {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int wc = 0;
                for (int c = 0; c < GRID_SIZE; ++c) {
                    if (board[r][c] != 0) {
                        if (c != wc) { board[r][wc] = board[r][c]; board[r][c] = 0; }
                        wc++;
                    }
                }
            }
        } else {
            for (int r = 0; r < GRID_SIZE; ++r) {
                int wc = GRID_SIZE - 1;
                for (int c = GRID_SIZE - 1; c >= 0; --c) {
                    if (board[r][c] != 0) {
                        if (c != wc) { board[r][wc] = board[r][c]; board[r][c] = 0; }
                        wc--;
                    }
                }
            }
        }
    }

    // Fast evaluation: BFS connectivity (sum of squares) + adjacency bonus
    double evaluate() const {
        long long sum_sq = 0;
        std::array<std::array<bool, GRID_SIZE>, GRID_SIZE> visited;
        for (int i = 0; i < GRID_SIZE; ++i) visited[i].fill(false);

        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] != 0 && !visited[r][c]) {
                    int flavor = board[r][c];
                    int comp_size = 0;
                    std::array<std::pair<int,int>, 100> q;
                    int head = 0, tail = 0;
                    q[tail++] = {r, c};
                    visited[r][c] = true;
                    while (head < tail) {
                        auto [cr, cc] = q[head++];
                        comp_size++;
                        for (int d = 0; d < 4; ++d) {
                            int nr = cr + DR[d], nc = cc + DC[d];
                            if (nr >= 0 && nr < GRID_SIZE && nc >= 0 && nc < GRID_SIZE &&
                                !visited[nr][nc] && board[nr][nc] == flavor) {
                                visited[nr][nc] = true;
                                q[tail++] = {nr, nc};
                            }
                        }
                    }
                    sum_sq += (long long)comp_size * comp_size;
                }
            }
        }

        // Also count adjacency for tiebreaking / gradient signal
        int adj = 0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            for (int c = 0; c < GRID_SIZE; ++c) {
                if (board[r][c] == 0) continue;
                if (c + 1 < GRID_SIZE && board[r][c + 1] == board[r][c]) adj++;
                if (r + 1 < GRID_SIZE && board[r + 1][c] == board[r][c]) adj++;
            }
        }

        return static_cast<double>(sum_sq) * 10.0 + static_cast<double>(adj);
    }
};

// Adaptive depth-3 search with time management
auto G_start_time = std::chrono::steady_clock::now();

inline double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - G_start_time).count();
}

// Depth-3 samples: {depth1_samples, depth2_samples, depth3_samples}
// These are small to fit in time budget
int G_d1_samples = 6;
int G_d2_samples = 3;
int G_d3_samples = 2;

double eval_depth3(const GameState& state, int turn, int depth) {
    if (depth == 0 || turn >= NUM_TURNS) {
        return state.evaluate();
    }

    int num_empty = state.count_empty_cells();
    if (num_empty == 0) return state.evaluate();

    int next_flavor = G_FLAVOR_SEQUENCE[turn];
    int max_samples;
    if (depth == 3) max_samples = G_d1_samples;
    else if (depth == 2) max_samples = G_d2_samples;
    else max_samples = G_d3_samples;

    int num_samples = std::min(max_samples, num_empty);
    if (num_samples == 0) return state.evaluate();

    double sum_eval = 0.0;
    for (int s = 0; s < num_samples; ++s) {
        int p_val;
        if (num_samples >= num_empty) {
            p_val = s + 1;
        } else {
            p_val = rng.uniform_int(1, num_empty);
        }

        GameState gs_placed = state;
        auto [r, c] = gs_placed.find_pth_empty_cell(p_val);
        gs_placed.place_candy(r, c, next_flavor);
        gs_placed.turn_num = turn + 1;

        double best_dir_eval = std::numeric_limits<double>::lowest();
        for (int d = 0; d < NUM_DIRECTIONS; ++d) {
            GameState gs_tilted = gs_placed;
            gs_tilted.apply_tilt(d);
            double val = eval_depth3(gs_tilted, turn + 1, depth - 1);
            if (val > best_dir_eval) best_dir_eval = val;
        }
        sum_eval += best_dir_eval;
    }
    return sum_eval / num_samples;
}

int decide_tilt_direction(const GameState& gs) {
    double best_eval = std::numeric_limits<double>::lowest();
    int best_dir = 0;

    for (int d = 0; d < NUM_DIRECTIONS; ++d) {
        GameState gs_tilted = gs;
        gs_tilted.apply_tilt(d);
        double val = eval_depth3(gs_tilted, gs.turn_num, 3);
        if (val > best_eval) {
            best_eval = val;
            best_dir = d;
        }
    }
    return best_dir;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    G_start_time = std::chrono::steady_clock::now();
    rng.seed(std::chrono::steady_clock::now().time_since_epoch().count());

    for (int t = 0; t < NUM_TURNS; ++t) {
        std::cin >> G_FLAVOR_SEQUENCE[t];
    }

    GameState gs;
    for (int t = 0; t < NUM_TURNS; ++t) {
        gs.turn_num = t + 1;
        int p_val;
        std::cin >> p_val;
        auto [r, c] = gs.find_pth_empty_cell(p_val);
        gs.place_candy(r, c, G_FLAVOR_SEQUENCE[t]);

        // Adaptive time management
        double elapsed = elapsed_seconds();
        double budget_per_turn = 1.85 / NUM_TURNS;
        double expected_time = budget_per_turn * (t + 1);

        if (elapsed > expected_time * 1.6) {
            G_d1_samples = 3;
            G_d2_samples = 2;
            G_d3_samples = 1;
        } else if (elapsed > expected_time * 1.3) {
            G_d1_samples = 5;
            G_d2_samples = 2;
            G_d3_samples = 1;
        } else if (t < 30) {
            // Early game: board sparse, eval fast, use more samples
            G_d1_samples = 8;
            G_d2_samples = 3;
            G_d3_samples = 2;
        } else {
            G_d1_samples = 6;
            G_d2_samples = 3;
            G_d3_samples = 2;
        }

        int dir = decide_tilt_direction(gs);
        std::cout << DIR_CHARS[dir] << std::endl;
        gs.apply_tilt(dir);
    }
    return 0;
}
